      "id": "AC-10",
      "given": "A verified user initiating a transfer of $1,500",
      "when": "The transaction is processed successfully",
      "then": "A notification is sent to the account holder about the transaction"
    },
    {
      "id": "AC-11",
      "given": "A verified user initiating a transfer of $999",
      "when": "The transaction is processed successfully",
      "then": "No transaction-amount notification is triggered"
    },
    {
      "id": "AC-12",
      "given": "A locked account",
      "when": "The user attempts to log in with correct credentials",
      "then": "The login is rejected and the user is informed to contact support"
    }
